console.log('MAGICBELL_EMAIL:', process.env.MAGICBELL_EMAIL);
console.log('ZEALT_RUN_ID:', process.env.ZEALT_RUN_ID);
console.log('MAGICBELL_API_KEY:', process.env.MAGICBELL_API_KEY);
console.log('MAGICBELL_SECRET_KEY:', process.env.MAGICBELL_SECRET_KEY ? 'present (masked)' : 'missing');

const { Client } = require('magicbell-js/user-client');
const { RequestBuilder } = require('magicbell-js/dist/commonjs/user-client/http/transport/request-builder.js');
const { ContentType } = require('magicbell-js/dist/commonjs/user-client/http/types.js');
const { z } = require('zod');
const jwt = require('jsonwebtoken');

const runId = process.env.ZEALT_RUN_ID;
const magicbellEmail = process.env.MAGICBELL_EMAIL;
const apiKey = process.env.MAGICBELL_API_KEY;
const secretKey = process.env.MAGICBELL_SECRET_KEY;

if (!runId || !magicbellEmail || !apiKey || !secretKey) {
  console.error('Missing required environment variables');
  process.exit(1);
}

// Construct the two possible emails
const email1 = `${magicbellEmail}+${runId}@gmail.com`;
const email2 = `${magicbellEmail.split('@')[0]}+${runId}@gmail.com`;

const emails = [email1, email2];
const topic = `test-topic-${runId}`;

async function unsubscribeEmail(email) {
  console.log(`Unsubscribing email: ${email} from topic: ${topic}`);

  // Generate User JWT
  const payload = {
    user_email: email,
    api_key: apiKey,
  };

  const token = jwt.sign(payload, secretKey, {
    algorithm: 'HS256',
    expiresIn: '1y',
  });

  // Instantiate Client
  const client = new Client({ token });

  // Dynamically add subscriptions.unsubscribe method
  client.subscriptions = {
    unsubscribe: async (topicName, data = {}, requestConfig) => {
      const request = new RequestBuilder()
        .setBaseUrl((requestConfig === null || requestConfig === void 0 ? void 0 : requestConfig.baseUrl) || client.config.baseUrl || client.config.environment || 'https://api.magicbell.com/v2')
